const src = $input.first().json;
const b = src.body && typeof src.body === 'object' ? src.body : src;
const projectId = String(b.project_id || src.project_id || '').trim();
let width = Number(b.width_ft !== undefined ? b.width_ft : src.width_ft) || 40;
let depth = Number(b.depth_ft !== undefined ? b.depth_ft : src.depth_ft) || 60;
let rooms = parseInt(b.rooms !== undefined ? b.rooms : src.rooms, 10);
if (!rooms || rooms < 2) { rooms = 6; }
if (rooms > 12) { rooms = 12; }
if (width < 20) { width = 20; }
if (width > 200) { width = 200; }
if (depth < 20) { depth = 20; }
if (depth > 200) { depth = 200; }
const designType = String(b.design_type || src.design_type || 'Standard').trim();
return [{ json: { project_id: projectId, width_ft: width, depth_ft: depth, rooms: rooms, design_type: designType } }];

const cfg = $('Normalize Plan Input').first().json;
const existing = $input.all().map(i => i.json).filter(r => r && r.plan_version !== undefined && r.plan_version !== null);
const nextVersion = existing.length ? Math.max.apply(null, existing.map(r => Number(r.plan_version) || 0)) + 1 : 1;
const W = Number(cfg.width_ft) || 40;
const D = Number(cfg.depth_ft) || 60;
const roomCount = Number(cfg.rooms) || 6;
const corridorD = 6;
const r2 = n => Math.round(n * 100) / 100;
const bandD = r2((D - corridorD) / 2);
const topCount = Math.ceil(roomCount / 2);
const botCount = roomCount - topCount;
const palette = ['#cfe8ff', '#ffe3cf', '#d8f5d0', '#f5d0e6', '#fff2b8', '#d0d8f5', '#e0cfff', '#cffff2', '#ffd6d6', '#e8ffcf', '#cfd9ff', '#ffe9f0'];
const roomNames = ['Living Room', 'Kitchen', 'Bedroom 1', 'Bedroom 2', 'Bathroom 1', 'Study', 'Dining', 'Utility', 'Bedroom 3', 'Bathroom 2', 'Balcony', 'Store Room'];
const rooms = [];
const addBand = (count, y0) => { if (count < 1) { return; } const w = r2(W / count); for (let i = 0; i < count; i++) { const idx = rooms.length; rooms.push({ name: roomNames[idx] || ('Room ' + (idx + 1)), x: r2(i * w), y: y0, w: w, d: bandD }); } };
addBand(topCount, 0);
addBand(botCount, r2(bandD + corridorD));
const Q = String.fromCharCode(34);
const attr = (k, v) => ' ' + k + '=' + Q + v + Q;
const S = 10;
const M = 50;
const svgW = W * S + M * 2;
const svgH = D * S + M * 2;
const parts = [];
parts.push('<svg' + attr('xmlns', 'http://www.w3.org/2000/svg') + attr('viewBox', '0 0 ' + svgW + ' ' + svgH) + attr('font-family', 'Arial, Helvetica, sans-serif') + '>');
parts.push('<rect' + attr('x', 0) + attr('y', 0) + attr('width', svgW) + attr('height', svgH) + attr('fill', '#ffffff') + '/>');
parts.push('<rect' + attr('x', M) + attr('y', M) + attr('width', W * S) + attr('height', D * S) + attr('fill', '#fafafa') + attr('stroke', '#1f2937') + attr('stroke-width', 4) + '/>');
parts.push('<rect' + attr('x', M) + attr('y', M + bandD * S) + attr('width', W * S) + attr('height', corridorD * S) + attr('fill', '#ececec') + attr('stroke', '#6b7280') + attr('stroke-width', 1) + '/>');
parts.push('<text' + attr('x', M + (W * S) / 2) + attr('y', M + bandD * S + (corridorD * S) / 2 + 5) + attr('text-anchor', 'middle') + attr('font-size', 14) + attr('fill', '#6b7280') + '>Corridor ' + W + ' ft x ' + corridorD + ' ft</text>');
rooms.forEach((r, i) => { const x = M + r.x * S; const y = M + r.y * S; const w = r.w * S; const d = r.d * S; parts.push('<rect' + attr('x', x) + attr('y', y) + attr('width', w) + attr('height', d) + attr('fill', palette[i % palette.length]) + attr('stroke', '#374151') + attr('stroke-width', 2) + '/>'); parts.push('<text' + attr('x', x + w / 2) + attr('y', y + d / 2 - 4) + attr('text-anchor', 'middle') + attr('font-size', 16) + attr('fill', '#111827') + '>' + r.name + '</text>'); parts.push('<text' + attr('x', x + w / 2) + attr('y', y + d / 2 + 16) + attr('text-anchor', 'middle') + attr('font-size', 12) + attr('fill', '#374151') + '>' + r.w + ' ft x ' + r.d + ' ft (' + r2(r.w * r.d) + ' sqft)</text>'); });
parts.push('<text' + attr('x', M + (W * S) / 2) + attr('y', M - 15) + attr('text-anchor', 'middle') + attr('font-size', 16) + attr('fill', '#111827') + '>Total width: ' + W + ' ft</text>');
parts.push('<text' + attr('x', 15) + attr('y', M + (D * S) / 2) + attr('font-size', 16) + attr('fill', '#111827') + attr('transform', 'rotate(-90 15 ' + (M + (D * S) / 2) + ')') + attr('text-anchor', 'middle') + '>Total depth: ' + D + ' ft</text>');
parts.push('</svg>');
const svg = parts.join('');
const boxes = rooms.map((r, i) => ({ name: r.name, x: r.x, y: 0, z: r.y, w: r.w, d: r.d, h: 10, color: palette[i % palette.length] }));
boxes.push({ name: 'Corridor', x: 0, y: 0, z: bandD, w: W, d: corridorD, h: 10, color: '#ececec' });
const model3d = { totalW: W, totalD: D, wallHeight: 10, boxes: boxes };
const dimensions = { total_sqft: r2(W * D), layout: 'two-room-bands-with-central-corridor', corridor_sqft: r2(W * corridorD), rooms: rooms.map(r => ({ name: r.name, sqft: r2(r.w * r.d), dimensions: r.w + ' ft x ' + r.d + ' ft' })) };
const finishes = { Standard: { flooring: 'Vitrified tiles', walls: 'Acrylic emulsion paint', doors: 'Flush doors with laminate finish', windows: 'UPVC sliding windows', rate: 1800 }, Premium: { flooring: 'Engineered wood and tiles', walls: 'Premium emulsion with accent panels', doors: 'Veneer finished solid core doors', windows: 'UPVC casement windows with mesh', rate: 2600 }, Luxury: { flooring: 'Italian marble and engineered wood', walls: 'Textured finish with wall paneling', doors: 'Teak wood doors', windows: 'Aluminium double glazed windows', rate: 4200 } };
const designType = finishes[cfg.design_type] ? cfg.design_type : 'Standard';
const finish = finishes[designType];
const materials = { design_type: designType, flooring: finish.flooring, wall_finish: finish.walls, doors: finish.doors, windows: finish.windows, estimated_material_rate_inr_per_sqft: finish.rate, estimated_material_cost_inr: Math.round(W * D * finish.rate) };
return [{ json: { project_id: cfg.project_id, plan_version: nextVersion, plan_2d_svg_url: 'data:image/svg+xml;utf8,' + encodeURIComponent(svg), plan_3d_model_url: 'data:application/json;utf8,' + encodeURIComponent(JSON.stringify(model3d)), dimensions_json: dimensions, materials_json: materials, generated_by: 'n8n@workflow.internal', design_notes: 'Generated by n8n DD-2 (' + roomCount + ' rooms, ' + W + ' ft x ' + D + ' ft, ' + designType + ' finish)' } }];
